8: /// A First In, First Out ring buffer.
9: pub fn RingBufferType(
10:     comptime T: type,
11:     comptime buffer_type: union(enum) {
12:         array: usize, // capacity
13:         slice, // (Capacity is passed to init() at runtime).
14:     },
15: ) type {
16:     return struct {
17:         const RingBuffer = @This();
18: 
19:         pub const count_max = switch (buffer_type) {
20:             .array => |count_max_| count_max_,
21:             .slice => {},
22:         };
23: 
24:         buffer: switch (buffer_type) {
25:             .array => |count_max_| [count_max_]T,
26:             .slice => []T,
27:         },
28: 
29:         /// The index of the slot with the first item, if any.
30:         index: usize = 0,
31: 
32:         /// The number of items in the buffer.
33:         count: usize = 0,
34: 
35:         pub const init = switch (buffer_type) {
36:             .array => init_array,
37:             .slice => init_slice,
38:         };
39: 
40:         fn init_array() RingBuffer {
41:             comptime assert(buffer_type == .array);
42:             return .{ .buffer = undefined };
43:         }
44: 
45:         fn init_slice(allocator: mem.Allocator, capacity: usize) !RingBuffer {
46:             comptime assert(buffer_type == .slice);
47:             assert(capacity > 0);
48: 
49:             const buffer = try allocator.alloc(T, capacity);
50:             errdefer allocator.free(buffer);
51:             return RingBuffer{ .buffer = buffer };
52:         }
53: 
54:         pub const deinit = switch (buffer_type) {
55:             .array => {},
56:             .slice => deinit_slice,
57:         };
58: 
59:         fn deinit_slice(self: *RingBuffer, allocator: mem.Allocator) void {
60:             comptime assert(buffer_type == .slice);
61:             allocator.free(self.buffer);
62:         }
63: 
64:         pub inline fn clear(self: *RingBuffer) void {
65:             self.index = 0;
66:             self.count = 0;
67:         }
68: 
69:         // TODO Add doc comments to these functions:
70:         pub inline fn head(self: RingBuffer) ?T {
71:             if (self.buffer.len == 0 or self.empty()) return null;
72:             return self.buffer[self.index];
73:         }
74: 
75:         pub inline fn head_ptr(self: *RingBuffer) ?*T {
76:             if (self.buffer.len == 0 or self.empty()) return null;
77:             return &self.buffer[self.index];
78:         }
79: 
80:         pub inline fn head_ptr_const(self: *const RingBuffer) ?*const T {
81:             if (self.buffer.len == 0 or self.empty()) return null;
82:             return &self.buffer[self.index];
83:         }
84: 
85:         pub inline fn tail(self: RingBuffer) ?T {
86:             if (self.buffer.len == 0 or self.empty()) return null;
87:             return self.buffer[(self.index + self.count - 1) % self.buffer.len];
88:         }
89: 
90:         pub inline fn tail_ptr(self: *RingBuffer) ?*T {
91:             if (self.buffer.len == 0 or self.empty()) return null;
92:             return &self.buffer[(self.index + self.count - 1) % self.buffer.len];
93:         }
94: 
95:         pub inline fn tail_ptr_const(self: *const RingBuffer) ?*const T {
96:             if (self.buffer.len == 0 or self.empty()) return null;
97:             return &self.buffer[(self.index + self.count - 1) % self.buffer.len];
98:         }
99: 
100:         pub fn get(self: *const RingBuffer, index: usize) ?T {
101:             if (self.buffer.len == 0) unreachable;
102: 
103:             if (index < self.count) {
104:                 return self.buffer[(self.index + index) % self.buffer.len];
105:             } else {
106:                 assert(index < self.buffer.len);
107:                 return null;
108:             }
109:         }
110: 
111:         pub inline fn get_ptr(self: *RingBuffer, index: usize) ?*T {
112:             if (self.buffer.len == 0) unreachable;
113: 
114:             if (index < self.count) {
115:                 return &self.buffer[(self.index + index) % self.buffer.len];
116:             } else {
117:                 assert(index < self.buffer.len);
118:                 return null;
119:             }
120:         }
121: 
122:         pub inline fn next_tail(self: RingBuffer) ?T {
123:             if (self.buffer.len == 0 or self.full()) return null;
124:             return self.buffer[(self.index + self.count) % self.buffer.len];
125:         }
126: 
127:         pub inline fn next_tail_ptr(self: *RingBuffer) ?*T {
128:             if (self.buffer.len == 0 or self.full()) return null;
129:             return &self.buffer[(self.index + self.count) % self.buffer.len];
130:         }
131: 
132:         pub inline fn next_tail_ptr_const(self: *const RingBuffer) ?*const T {
133:             if (self.buffer.len == 0 or self.full()) return null;
134:             return &self.buffer[(self.index + self.count) % self.buffer.len];
135:         }
136: 
137:         pub inline fn advance_head(self: *RingBuffer) void {
138:             self.index += 1;
139:             self.index %= self.buffer.len;
140:             self.count -= 1;
141:         }
142: 
143:         pub fn advance_head_many(self: *RingBuffer, discard: u64) void {
144:             assert(discard <= self.count);
145:             if (self.buffer.len == 0) return;
146: 
147:             self.index += discard;
148:             self.index %= self.buffer.len;
149:             self.count -= discard;
150:         }
151: 
152:         pub inline fn retreat_head(self: *RingBuffer) void {
153:             assert(self.count < self.buffer.len);
154: 
155:             // This condition is covered by the above assert, but it is necessary to make it
156:             // explicitly unreachable so that the compiler doesn't error when computing (at
157:             // comptime) `buffer.len - 1` for a zero-capacity array-backed ring buffer.
158:             if (self.buffer.len == 0) unreachable;
159: 
160:             self.index += self.buffer.len - 1;
161:             self.index %= self.buffer.len;
162:             self.count += 1;
163:         }
164: 
165:         pub inline fn advance_tail(self: *RingBuffer) void {
166:             assert(self.count < self.buffer.len);
167:             self.count += 1;
168:         }
169: 
170:         pub inline fn retreat_tail(self: *RingBuffer) void {
171:             self.count -= 1;
172:         }
173: 
174:         /// Returns whether the ring buffer is completely full.
175:         pub inline fn full(self: RingBuffer) bool {
176:             return self.count == self.buffer.len;
177:         }
178: 
179:         pub inline fn spare_capacity(self: RingBuffer) usize {
180:             return self.buffer.len - self.count;
181:         }
182: 
183:         /// Returns whether the ring buffer is completely empty.
184:         pub inline fn empty(self: RingBuffer) bool {
185:             return self.count == 0;
186:         }
187: 
188:         // Higher level, less error-prone wrappers:
189: 
190:         pub fn push_head(self: *RingBuffer, item: T) error{NoSpaceLeft}!void {
191:             if (self.count == self.buffer.len) return error.NoSpaceLeft;
192:             self.push_head_assume_capacity(item);
193:         }
194: 
195:         pub fn push_head_assume_capacity(self: *RingBuffer, item: T) void {
196:             assert(self.count < self.buffer.len);
197: 
198:             self.retreat_head();
199:             self.head_ptr().?.* = item;
200:         }
201: 
202:         /// Add an element to the RingBuffer. Returns an error if the buffer
203:         /// is already full and the element could not be added.
204:         pub fn push(self: *RingBuffer, item: T) error{NoSpaceLeft}!void {
205:             const ptr = self.next_tail_ptr() orelse return error.NoSpaceLeft;
206:             ptr.* = item;
207:             self.advance_tail();
208:         }
209: 
210:         /// Add an element to a RingBuffer, and assert that the capacity is sufficient.
211:         pub fn push_assume_capacity(self: *RingBuffer, item: T) void {
212:             self.push(item) catch |err| switch (err) {
213:                 error.NoSpaceLeft => unreachable,
214:             };
215:         }
216: 
217:         pub fn push_slice(self: *RingBuffer, items: []const T) error{NoSpaceLeft}!void {
218:             if (self.buffer.len == 0) return error.NoSpaceLeft;
219:             if (self.count + items.len > self.buffer.len) return error.NoSpaceLeft;
220: 
221:             const pre_wrap_start = (self.index + self.count) % self.buffer.len;
222:             const pre_wrap_count = @min(items.len, self.buffer.len - pre_wrap_start);
223:             const post_wrap_count = items.len - pre_wrap_count;
224: 
225:             const pre_wrap_items = items[0..pre_wrap_count];
226:             const post_wrap_items = items[pre_wrap_count..];
227:             stdx.copy_disjoint(.inexact, T, self.buffer[pre_wrap_start..], pre_wrap_items);
228:             stdx.copy_disjoint(.exact, T, self.buffer[0..post_wrap_count], post_wrap_items);
229: 
230:             self.count += items.len;
231:         }
232: 
233:         /// Remove and return the next item, if any.
234:         pub fn pop(self: *RingBuffer) ?T {
235:             const result = self.head() orelse return null;
236:             self.advance_head();
237:             return result;
238:         }
239: 
240:         /// Remove and return the last item, if any.
241:         pub fn pop_tail(self: *RingBuffer) ?T {
242:             const result = self.tail() orelse return null;
243:             self.retreat_tail();
244:             return result;
245:         }
246: 
247:         pub const Iterator = struct {
248:             ring: *const RingBuffer,
249:             count: usize = 0,
250: 
251:             pub fn next(it: *Iterator) ?T {
252:                 if (it.next_ptr()) |item| {
253:                     return item.*;
254:                 }
255:                 return null;
256:             }
257: 
258:             pub fn next_ptr(it: *Iterator) ?*const T {
259:                 assert(it.count <= it.ring.count);
260:                 if (it.ring.buffer.len == 0) return null;
261:                 if (it.count == it.ring.count) return null;
262:                 defer it.count += 1;
263: 
264:                 return &it.ring.buffer[(it.ring.index + it.count) % it.ring.buffer.len];
265:             }
266:         };
267: 
268:         /// Returns an iterator to iterate through all `count` items in the ring buffer.
269:         /// The iterator is invalidated if the ring buffer is advanced.
270:         pub fn iterator(self: *const RingBuffer) Iterator {
271:             return .{ .ring = self };
272:         }
273: 
274:         pub const IteratorMutable = struct {
275:             ring: *RingBuffer,
276:             count: usize = 0,
277: 
278:             pub fn next_ptr(it: *IteratorMutable) ?*T {
279:                 assert(it.count <= it.ring.count);
280:                 if (it.ring.buffer.len == 0) return null;
281:                 if (it.count == it.ring.count) return null;
282:                 defer it.count += 1;
283: 
284:                 return &it.ring.buffer[(it.ring.index + it.count) % it.ring.buffer.len];
285:             }
286:         };
287: 
288:         pub fn iterator_mutable(self: *RingBuffer) IteratorMutable {
289:             return .{ .ring = self };
290:         }
291:     };
292: }
