296: fn test_iterator(comptime T: type, ring: *T, values: []const u32) !void {
297:     const ring_index = ring.index;
298: 
299:     inline for (.{ .immutable, .mutable }) |mutability| {
300:         for (0..2) |_| {
301:             var iterator = switch (mutability) {
302:                 .immutable => ring.iterator(),
303:                 .mutable => ring.iterator_mutable(),
304:                 else => unreachable,
305:             };
306:             var index: u32 = 0;
307:             switch (mutability) {
308:                 .immutable => while (iterator.next()) |item| {
309:                     try testing.expectEqual(values[index], item);
310:                     index += 1;
311:                 },
312:                 .mutable => {
313:                     const permutation = @divFloor(std.math.maxInt(u32), 2);
314:                     while (iterator.next_ptr()) |item| {
315:                         try testing.expectEqual(values[index], item.*);
316:                         item.* += permutation + index;
317:                         index += 1;
318:                     }
319:                     iterator = ring.iterator_mutable();
320:                     var check_index: u32 = 0;
321:                     while (iterator.next_ptr()) |item| {
322:                         try testing.expectEqual(
323:                             values[check_index] + permutation + check_index,
324:                             item.*,
325:                         );
326:                         item.* -= permutation + check_index;
327:                         check_index += 1;
328:                     }
329:                     try testing.expectEqual(index, check_index);
330:                 },
331:                 else => unreachable,
332:             }
333:             try testing.expectEqual(values.len, index);
334:         }
335: 
336:         try testing.expectEqual(ring_index, ring.index);
337:     }
338: }
