1: const std = @import("std");
2: const assert = std.debug.assert;
3: const mem = std.mem;
4: 
5: const stdx = @import("stdx");
6: const constants = @import("constants.zig");
7: 
8: const vsr = @import("vsr.zig");
9: const Header = vsr.Header;
10: const StackType = @import("./stack.zig").StackType;
11: 
12: comptime {
13:     // message_size_max must be a multiple of sector_size for Direct I/O
14:     assert(constants.message_size_max % constants.sector_size == 0);
15: }
16: 
17: pub const Options = union(vsr.ProcessType) {
18:     replica: Replica,
19:     client,
20: 
21:     const Replica = struct {
22:         members_count: u8,
23:         pipeline_requests_limit: u32,
24:         message_bus: enum { tcp, testing },
25:     };
26: 
27:     /// The number of messages allocated at initialization by the message pool.
28:     fn messages_max(options: *const Options) u32 {
29:         return switch (options.*) {
30:             .client => messages_max_client(),
31:             .replica => |replica| messages_max_replica(replica),
32:         };
33:     }
34: 
35:     fn messages_max_client() u32 {
36:         var sum: u32 = 0;
37: 
38:         sum += constants.replicas_max; // Connection.recv_buffer
39:         // Connection.send_queue:
40:         sum += constants.replicas_max * constants.connection_send_queue_max_client;
41:         sum += 1; // Client.request_inflight
42:         // Handle bursts.
43:         // (e.g. Connection.parse_message(), or sending a ping when the send queue is full).
44:         sum += 1;
45: 
46:         // This conditions is necessary (but not sufficient) to prevent deadlocks.
47:         assert(sum > 1);
48:         return sum;
49:     }
50: 
51:     // The number of full-sized messages allocated at initialization by the replica message
52:     // pool. There must be enough messages to ensure that the replica can always progress,
53:     // to avoid deadlock.
54:     fn messages_max_replica(replica: Options.Replica) u32 {
55:         assert(replica.members_count > 0);
56:         assert(replica.members_count <= constants.members_max);
57:         assert(replica.pipeline_requests_limit >= 0);
58:         assert(replica.pipeline_requests_limit <= constants.pipeline_request_queue_max);
59: 
60:         var sum: u32 = 0;
61: 
62:         const pipeline_limit =
63:             constants.pipeline_prepare_queue_max + replica.pipeline_requests_limit;
64: 
65:         sum += constants.journal_iops_read_max; // Journal reads
66:         sum += constants.journal_iops_write_max; // Journal writes
67:         sum += constants.client_replies_iops_read_max; // Client-reply reads
68:         sum += constants.client_replies_iops_write_max; // Client-reply writes
69:         // Replica.grid_reads (Replica.BlockRead)
70:         sum += constants.grid_repair_reads_max;
71:         sum += 1; // Replica.loopback_queue
72:         sum += pipeline_limit; // Replica.Pipeline{Queue|Cache}
73:         sum += 1; // Replica.commit_prepare
74:         sum += 1; // Replica.sync_view
75:         // Replica.join_view_from_all_replicas quorum:
76:         // All other quorums are bitsets.
77:         //
78:         // This should be set to the runtime replica_count, but we don't know that precisely
79:         // yet, so we may guess high. (We can't differentiate between replicas and
80:         // standbys.)
81:         sum += @min(replica.members_count, constants.replicas_max);
82:         sum += 1; // Handle bursts (e.g. Connection.parse_message)
83:         // Handle Replica.commit_op's reply:
84:         // (This is separate from the burst +1 because they may occur concurrently).
85:         sum += 1;
86: 
87:         switch (replica.message_bus) {
88:             .tcp => {
89:                 // The maximum number of simultaneous open connections on the server.
90:                 // -1 since we never connect to ourself.
91:                 const connections_max = replica.members_count + pipeline_limit - 1;
92:                 sum += connections_max; // Connection.recv_buffer
93:                 // Connection.send_queue:
94:                 sum += connections_max * constants.connection_send_queue_max_replica;
95:             },
96:             .testing => {},
97:         }
98: 
99:         // This conditions is necessary (but not sufficient) to prevent deadlocks.
100:         assert(sum > constants.replicas_max);
101:         return sum;
102:     }
103: };
