105: /// A pool of reference-counted Messages, memory for which is allocated only once during
106: /// initialization and reused thereafter. The messages_max values determine the size of this pool.
107: pub const MessagePool = struct {
108:     pub const Message = extern struct {
109:         pub const Reserved = CommandMessageType(.reserved);
110:         pub const Ping = CommandMessageType(.ping);
111:         pub const Pong = CommandMessageType(.pong);
112:         pub const PingClient = CommandMessageType(.ping_client);
113:         pub const PongClient = CommandMessageType(.pong_client);
114:         pub const Request = CommandMessageType(.request);
115:         pub const Prepare = CommandMessageType(.prepare);
116:         pub const PrepareOk = CommandMessageType(.prepare_ok);
117:         pub const Reply = CommandMessageType(.reply);
118:         pub const Commit = CommandMessageType(.commit);
119:         pub const ExitView = CommandMessageType(.exit_view);
120:         pub const JoinView = CommandMessageType(.join_view);
121:         pub const View = CommandMessageType(.view);
122:         pub const RequestView = CommandMessageType(.request_view);
123:         pub const RequestHeaders = CommandMessageType(.request_headers);
124:         pub const RequestPrepare = CommandMessageType(.request_prepare);
125:         pub const RequestReply = CommandMessageType(.request_reply);
126:         pub const Headers = CommandMessageType(.headers);
127:         pub const Eviction = CommandMessageType(.eviction);
128:         pub const RequestBlocks = CommandMessageType(.request_blocks);
129:         pub const Block = CommandMessageType(.block);
130: 
131:         // TODO Avoid the extra level of indirection.
132:         // (https://github.com/tigerbeetle/tigerbeetle/pull/1295#discussion_r1394265250)
133:         header: *Header,
134:         buffer: *align(constants.sector_size) [constants.message_size_max]u8,
135:         references: u32 = 0,
136:         link: FreeList.Link,
137: 
138:         /// Increment the reference count of the message and return the same pointer passed.
139:         pub fn ref(message: *Message) *Message {
140:             assert(message.references > 0);
141:             assert(message.link.next == null);
142: 
143:             message.references += 1;
144:             return message;
145:         }
146: 
147:         pub fn body_used(message: *const Message) []align(@sizeOf(Header)) u8 {
148:             return message.buffer[@sizeOf(Header)..message.header.size];
149:         }
150: 
151:         /// NOTE:
152:         /// - Does *not* alter the reference count.
153:         /// - Does *not* verify the command. (Use this function for constructing the message.)
154:         pub fn build(
155:             message: *Message,
156:             comptime command: vsr.Command,
157:         ) *CommandMessageType(command) {
158:             return @ptrCast(message);
159:         }
160: 
161:         /// NOTE: Does *not* alter the reference count.
162:         pub fn into(
163:             message: *Message,
164:             comptime command: vsr.Command,
165:         ) ?*CommandMessageType(command) {
166:             if (message.header.command != command) return null;
167:             return @ptrCast(message);
168:         }
169: 
170:         pub const AnyMessage = stdx.EnumUnionType(vsr.Command, MessagePointerType);
171: 
172:         fn MessagePointerType(comptime command: vsr.Command) type {
173:             return *CommandMessageType(command);
174:         }
175: 
176:         /// NOTE: Does *not* alter the reference count.
177:         pub fn into_any(message: *Message) AnyMessage {
178:             switch (message.header.command) {
179:                 inline else => |command| {
180:                     return @unionInit(AnyMessage, @tagName(command), message.into(command).?);
181:                 },
182:             }
183:         }
184:     };
185: 
186:     const FreeList = StackType(Message);
187:     /// List of currently unused messages.
188:     free_list: StackType(Message),
189: 
190:     messages_max: usize,
191:     messages: []Message,
192:     buffers: []align(constants.sector_size) [constants.message_size_max]u8,
193: 
194:     pub fn init(
195:         allocator: mem.Allocator,
196:         options: Options,
197:     ) error{OutOfMemory}!MessagePool {
198:         return MessagePool.init_capacity(allocator, options.messages_max());
199:     }
200: 
201:     pub fn init_capacity(
202:         allocator: mem.Allocator,
203:         messages_max: u32,
204:     ) error{OutOfMemory}!MessagePool {
205:         const buffers = try allocator.alignedAlloc(
206:             [constants.message_size_max]u8,
207:             constants.sector_size,
208:             messages_max,
209:         );
210:         errdefer allocator.free(buffers);
211: 
212:         const messages = try allocator.alloc(Message, messages_max);
213:         errdefer allocator.free(messages);
214: 
215:         var free_list = FreeList.init(.{
216:             .capacity = messages_max,
217:             .verify_push = false,
218:         });
219:         for (messages, buffers) |*message, *buffer| {
220:             message.* = .{ .header = undefined, .buffer = buffer, .link = .{} };
221:             free_list.push(message);
222:         }
223: 
224:         return .{
225:             .free_list = free_list,
226:             .messages_max = messages_max,
227:             .messages = messages,
228:             .buffers = buffers,
229:         };
230:     }
231: 
232:     /// Frees all messages that were unused or returned to the pool via unref().
233:     pub fn deinit(pool: *MessagePool, allocator: mem.Allocator) void {
234:         // If the MessagePool is being deinitialized, all messages should have already been
235:         // released to the pool.
236:         assert(pool.free_list.count() == pool.messages_max);
237:         assert(pool.messages.len == pool.messages_max);
238:         assert(pool.buffers.len == pool.messages_max);
239:         allocator.free(pool.messages);
240:         allocator.free(pool.buffers);
241:         pool.* = undefined;
242:     }
243: 
244:     pub fn GetMessageType(comptime command: ?vsr.Command) type {
245:         if (command) |c| {
246:             return *CommandMessageType(c);
247:         } else {
248:             return *Message;
249:         }
250:     }
251: 
252:     /// Get an unused message with a buffer of constants.message_size_max.
253:     /// The returned message has exactly one reference.
254:     pub fn get_message(pool: *MessagePool, comptime command: ?vsr.Command) GetMessageType(command) {
255:         if (command) |c| {
256:             return pool.get_message_base().build(c);
257:         } else {
258:             return pool.get_message_base();
259:         }
260:     }
261: 
262:     fn get_message_base(pool: *MessagePool) *Message {
263:         const message = pool.free_list.pop().?;
264:         assert(message.link.next == null);
265:         message.header = mem.bytesAsValue(Header, message.buffer[0..@sizeOf(Header)]);
266:         assert(message.references == 0);
267: 
268:         message.references = 1;
269:         return message;
270:     }
271: 
272:     /// Decrement the reference count of the message, possibly freeing it.
273:     ///
274:     /// `@TypeOf(message)` is one of:
275:     /// - `*Message`
276:     /// - `*MessageType(command)` for any `command`.
277:     pub fn unref(pool: *MessagePool, message: anytype) void {
278:         assert(@typeInfo(@TypeOf(message)) == .pointer);
279:         assert(!@typeInfo(@TypeOf(message)).pointer.is_const);
280: 
281:         if (@TypeOf(message) == *Message) {
282:             pool.unref_base(message);
283:         } else {
284:             pool.unref_base(message.base());
285:         }
286:     }
287: 
288:     fn unref_base(pool: *MessagePool, message: *Message) void {
289:         assert(message.link.next == null);
290: 
291:         message.references -= 1;
292:         if (message.references == 0) {
293:             message.header = undefined;
294:             if (constants.verify) {
295:                 @memset(message.buffer, undefined);
296:             }
297:             pool.free_list.push(message);
298:         }
299:     }
300: };
301: 
302: fn CommandMessageType(comptime command: vsr.Command) type {
303:     const CommandHeaderUnified = Header.Type(command);
304: 
305:     return extern struct {
306:         const CommandMessage = @This();
307:         const CommandHeader = CommandHeaderUnified;
308:         const Message = MessagePool.Message;
309: 
310:         // The underlying structure of Message and CommandMessage should be identical, so that their
311:         // memory can be cast back-and-forth.
312:         comptime {
313:             assert(@sizeOf(Message) == @sizeOf(CommandMessage));
314: 
315:             for (
316:                 std.meta.fields(Message),
317:                 std.meta.fields(CommandMessage),
318:             ) |message_field, command_message_field| {
319:                 assert(std.mem.eql(u8, message_field.name, command_message_field.name));
320:                 assert(@sizeOf(message_field.type) == @sizeOf(command_message_field.type));
321:                 assert(@offsetOf(Message, message_field.name) ==
322:                     @offsetOf(CommandMessage, command_message_field.name));
323:             }
324:         }
325: 
326:         /// Points into `buffer`.
327:         header: *CommandHeader,
328:         buffer: *align(constants.sector_size) [constants.message_size_max]u8,
329:         references: u32,
330:         link: MessagePool.FreeList.Link,
331: 
332:         pub fn base(message: *CommandMessage) *Message {
333:             return @ptrCast(message);
334:         }
335: 
336:         pub fn base_const(message: *const CommandMessage) *const Message {
337:             return @ptrCast(message);
338:         }
339: 
340:         pub fn ref(message: *CommandMessage) *CommandMessage {
341:             return @ptrCast(message.base().ref());
342:         }
343: 
344:         pub fn body_used(message: *const CommandMessage) []align(@sizeOf(Header)) u8 {
345:             return message.base_const().body_used();
346:         }
347:     };
348: }
