1: const std = @import("std");
2: const assert = std.debug.assert;
3: const mem = std.mem;
4: 
5: const DynamicBitSetUnmanaged = std.bit_set.DynamicBitSetUnmanaged;
6: const MaskInt = DynamicBitSetUnmanaged.MaskInt;
7: 
8: const vsr = @import("../vsr.zig");
9: const stdx = vsr.stdx;
10: const KiB = stdx.KiB;
11: const ewah = vsr.ewah(FreeSet.Word);
12: const constants = vsr.constants;
13: 
14: const div_ceil = stdx.div_ceil;
15: const maybe = stdx.maybe;
