17: /// This is logically a range of addresses within the FreeSet, but its actual fields are block
18: /// indexes for ease of calculation.
19: ///
20: /// A reservation covers a range of both free and acquired blocks — when it is first created,
21: /// it is guaranteed to cover exactly as many free blocks as were requested by `reserve()`.
22: pub const Reservation = struct {
23:     block_base: usize,
24:     block_count: usize,
25:     /// An identifier for each reservation cycle, to verify that old reservations are not reused.
26:     session: usize,
27: };
28: 
29: /// The 0 address is reserved for usage as a sentinel and will never be returned by acquire().
30: ///
31: /// Concurrent callers must reserve free blocks before acquiring them to ensure that
32: /// acquisition order is deterministic despite concurrent jobs acquiring blocks in
33: /// nondeterministic order.
34: ///
35: /// The reservation lifecycle is:
36: ///
37: ///   1. Reserve: In deterministic order, each job (e.g. compaction) calls `reserve()` to
38: ///      reserve the upper bound of blocks that it may need to acquire to complete.
39: ///   2. Acquire: The jobs run concurrently. Each job acquires blocks only from its respective
40: ///      reservation (via `acquire()`).
41: ///   3. Forfeit: When a job finishes, it calls `forfeit()` to drop its reservation.
42: ///   4. Done: When all pending reservations are forfeited, the reserved (but unacquired) space
43: ///      is reclaimed.
44: ///
45: pub const FreeSet = struct {
46:     pub const Word = u64;
47:     pub const BitsetKind = enum {
48:         blocks_acquired,
49:         blocks_released,
50:     };
51:     const BlocksReleasedPriorCheckpointDurability = std.AutoArrayHashMapUnmanaged(u64, void);
52: 
53:     // Free set is stored in the grid (see `CheckpointTrailer`) and is not available until the
54:     // relevant blocks are fetched from disk (or other replicas) and decoded.
55:     //
56:     // Without the free set, only blocks belonging to the free set might be read and no blocks can
57:     // be written.
58:     opened: bool = false,
59: 
60:     /// Whether the current checkpoint is durable.
61:     checkpoint_durable: bool = false,
62: 
63:     /// If a shard has any free blocks, the corresponding index bit is zero.
64:     /// If a shard has no free blocks, the corresponding index bit is one.
65:     index: DynamicBitSetUnmanaged,
66: 
67:     /// The maximum number of blocks the free set is allowed to reserve (driven by --limit-storage).
68:     blocks_count_limit: u64,
69: 
70:     /// Set bits indicate acquired blocks; unset bits indicate free blocks.
71:     blocks_acquired: DynamicBitSetUnmanaged,
72: 
73:     /// Set bits indicate blocks released in the current checkpoint, to be freed when the next
74:     /// checkpoint becomes durable.
75:     blocks_released: DynamicBitSetUnmanaged,
76: 
77:     /// Temporarily holds blocks released prior durability of the current checkpoint, to be freed
78:     /// when the next checkpoint becomes durable. These blocks are moved to blocks_released once the
79:     /// current checkpoint becomes durable.
80:     blocks_released_prior_checkpoint_durability: BlocksReleasedPriorCheckpointDurability,
81: 
82:     /// The number of blocks that are reserved, counting both acquired and free blocks
83:     /// from the start of `blocks_acquired`.
84:     /// Alternatively, the index of the first non-reserved block in `blocks_acquired`.
85:     reservation_blocks: usize = 0,
86: 
87:     /// The number of active reservations.
88:     reservation_count: usize = 0,
89: 
90:     /// Verify that when the caller transitions from creating reservations to forfeiting them,
91:     /// all reservations must be forfeited before additional reservations are made.
92:     reservation_state: enum {
93:         reserving,
94:         forfeiting,
95:     } = .reserving,
96: 
97:     /// Verifies that reservations are not allocated from or forfeited when they should not be.
98:     reservation_session: usize = 1,
99: 
100:     // Each shard is 8 cache lines because the CPU line fill buffer can fetch 10 lines in parallel.
101:     // And 8 is fast for division when computing the shard of a block.
102:     // Since the shard is scanned sequentially, the prefetching amortizes the cost of the single
103:     // cache miss. It also reduces the size of the index.
104:     //
105:     // e.g. 10TiB disk ÷ 64KiB/block ÷ 512*8 blocks/shard ÷ 8 shards/byte = 5120B index
106:     const shard_cache_lines = 8;
107:     pub const shard_bits = shard_cache_lines * constants.cache_line_size * @bitSizeOf(u8);
108:     comptime {
109:         assert(shard_bits == 4096);
110:         assert(@bitSizeOf(MaskInt) == 64);
111:         // Ensure there are no wasted padding bits at the end of the index.
112:         assert(shard_bits % @bitSizeOf(MaskInt) == 0);
113:     }
114: 
115:     pub fn init(allocator: mem.Allocator, options: struct {
116:         grid_size_limit: usize,
117:         blocks_released_prior_checkpoint_durability_max: usize,
118:     }) !FreeSet {
119:         const blocks_count = block_count_max(options.grid_size_limit);
120:         assert(blocks_count % shard_bits == 0);
121:         assert(blocks_count % @bitSizeOf(Word) == 0);
122: 
123:         // Every block bit is covered by exactly one index bit.
124:         const shards_count = @divExact(blocks_count, shard_bits);
125:         var index = try DynamicBitSetUnmanaged.initEmpty(allocator, shards_count);
126:         errdefer index.deinit(allocator);
127: 
128:         var blocks_acquired = try DynamicBitSetUnmanaged.initEmpty(allocator, blocks_count);
129:         errdefer blocks_acquired.deinit(allocator);
130: 
131:         var blocks_released = try DynamicBitSetUnmanaged.initEmpty(allocator, blocks_count);
132:         errdefer blocks_released.deinit(allocator);
133: 
134:         var released_prior_checkpoint_durability: BlocksReleasedPriorCheckpointDurability = .{};
135:         try released_prior_checkpoint_durability.ensureTotalCapacity(
136:             allocator,
137:             options.blocks_released_prior_checkpoint_durability_max +
138:                 // `blocks_released` and `blocks_acquired` encoded in the CheckpointTrailer are
139:                 // released at checkpoint (see `mark_checkpoint_not_durable` in grid.zig).
140:                 2 * vsr.checkpoint_trailer.block_count_for_trailer_size(
141:                     ewah.encode_size_max(blocks_count),
142:                 ),
143:         );
144:         errdefer released_prior_checkpoint_durability.deinit();
145: 
146:         assert(index.count() == 0);
147:         assert(blocks_acquired.count() == 0);
148:         assert(blocks_released.count() == 0);
149:         assert(released_prior_checkpoint_durability.count() == 0);
150: 
151:         return FreeSet{
152:             .index = index,
153:             .blocks_count_limit = @divFloor(options.grid_size_limit, constants.block_size),
154:             .blocks_acquired = blocks_acquired,
155:             .blocks_released = blocks_released,
156:             .blocks_released_prior_checkpoint_durability = released_prior_checkpoint_durability,
157:         };
158:     }
159:     pub fn deinit(set: *FreeSet, allocator: mem.Allocator) void {
160:         set.index.deinit(allocator);
161:         set.blocks_acquired.deinit(allocator);
162:         set.blocks_released.deinit(allocator);
163:         set.blocks_released_prior_checkpoint_durability.deinit(allocator);
164:     }
165: 
166:     pub fn reset(set: *FreeSet) void {
167:         for ([_]*DynamicBitSetUnmanaged{
168:             &set.index,
169:             &set.blocks_acquired,
170:             &set.blocks_released,
171:         }) |bitset| {
172:             var it = bitset.iterator(.{});
173:             while (it.next()) |bit| bitset.unset(bit);
174:         }
175: 
176:         set.blocks_released_prior_checkpoint_durability.clearRetainingCapacity();
177: 
178:         set.* = .{
179:             .index = set.index,
180:             .blocks_count_limit = set.blocks_count_limit,
181:             .blocks_acquired = set.blocks_acquired,
182:             .blocks_released = set.blocks_released,
183:             .blocks_released_prior_checkpoint_durability = set
184:                 .blocks_released_prior_checkpoint_durability,
185:             .reservation_session = set.reservation_session +% 1,
186:         };
187: 
188:         assert(set.index.count() == 0);
189:         assert(set.blocks_acquired.count() == 0);
190:         assert(set.blocks_released.count() == 0);
191:         assert(set.blocks_released_prior_checkpoint_durability.count() == 0);
192: 
193:         assert(!set.opened);
194:     }
195: 
196:     /// Opens a free set. Needs two inputs:
197:     ///
198:     ///   - the byte buffers with the ewah-encoded acquired and released bitsets,
199:     ///   - the list of block addresses used to store both the encoded bitsets in the grid.
200:     ///
201:     /// Block addresses themselves are not a part of the encoded bitset for acquired blocks,
202:     /// see CheckpointTrailer for details.
203:     pub fn open(set: *FreeSet, options: struct {
204:         encoded: struct {
205:             blocks_acquired: []const []align(@alignOf(Word)) const u8,
206:             blocks_released: []const []align(@alignOf(Word)) const u8,
207:         },
208:         free_set_block_addresses: struct {
209:             blocks_acquired: []const u64,
210:             blocks_released: []const u64,
211:         },
212:     }) void {
213:         assert(!set.opened);
214:         assert((options.encoded.blocks_acquired.len == 0 and
215:             options.encoded.blocks_released.len == 0) ==
216:             (options.free_set_block_addresses.blocks_acquired.len == 0 and
217:                 options.free_set_block_addresses.blocks_released.len == 0));
218:         set.decode_chunks(
219:             options.encoded.blocks_acquired,
220:             options.encoded.blocks_released,
221:         );
222:         set.mark_released(options.free_set_block_addresses.blocks_acquired);
223:         set.mark_released(options.free_set_block_addresses.blocks_released);
224:         set.opened = true;
225:     }
226: 
227:     // A shortcut to initialize an empty free set for tests.
228:     pub fn init_empty(allocator: mem.Allocator, blocks_count: usize) !FreeSet {
229:         comptime assert(constants.verify);
230:         var set = try init(allocator, .{
231:             .grid_size_limit = blocks_count * constants.block_size,
232:             .blocks_released_prior_checkpoint_durability_max = 0,
233:         });
234:         errdefer set.deinit(allocator);
235: 
236:         assert(!set.opened);
237:         assert(!set.checkpoint_durable);
238:         return set;
239:     }
240: 
241:     // A shortcut to initialize and open an empty free set for tests.
242:     pub fn open_empty(allocator: mem.Allocator, blocks_count: usize) !FreeSet {
243:         comptime assert(constants.verify);
244:         var set = try init(allocator, .{
245:             .grid_size_limit = blocks_count * constants.block_size,
246:             .blocks_released_prior_checkpoint_durability_max = 0,
247:         });
248:         errdefer set.deinit(allocator);
249: 
250:         set.open(.{
251:             .encoded = .{ .blocks_acquired = &.{}, .blocks_released = &.{} },
252:             .free_set_block_addresses = .{ .blocks_acquired = &.{}, .blocks_released = &.{} },
253:         });
254:         // Mark checkpoint as durable so tests use blocks_released for block releases.
255:         // blocks_released_prior_checkpoint_durable is required to ensure correctness across
256:         // multiple replicas, while tests check the following flows in a single process:
257:         // * Block acquisition-release
258:         // * Bitset encoding-decoding
259:         set.checkpoint_durable = true;
260: 
261:         assert(set.opened);
262:         assert(set.count_free() == blocks_count);
263:         assert(set.count_released() == 0);
264:         return set;
265:     }
