273:     /// Returns the number of active reservations.
274:     pub fn count_reservations(set: FreeSet) usize {
275:         assert(set.opened);
276:         return set.reservation_count;
277:     }
278: 
279:     /// Returns the number of free blocks.
280:     pub fn count_free(set: FreeSet) usize {
281:         assert(set.opened);
282:         return set.blocks_acquired.capacity() - set.blocks_acquired.count();
283:     }
284: 
285:     /// Returns the number of acquired blocks.
286:     pub fn count_acquired(set: FreeSet) usize {
287:         assert(set.opened);
288:         return set.blocks_acquired.count();
289:     }
290: 
291:     /// Returns the number of released blocks.
292:     pub fn count_released(set: FreeSet) usize {
293:         assert(set.opened);
294:         return set.blocks_released.count() +
295:             set.blocks_released_prior_checkpoint_durability.count();
