298:     /// Returns the address of the highest acquired block.
299:     pub fn highest_address_acquired(set: FreeSet) ?u64 {
300:         assert(set.opened);
301:         var it = set.blocks_acquired.iterator(.{
302:             .kind = .set,
303:             .direction = .reverse,
304:         });
305: 
306:         if (it.next()) |block| {
307:             const address = block + 1;
308:             return address;
309:         } else {
310:             // All blocks are free.
311:             assert(set.blocks_acquired.count() == 0);
312:             return null;
313:         }
314:     }
315: 
316:     /// Returns the address of the highest released block.
317:     pub fn highest_address_released(set: FreeSet) ?u64 {
318:         assert(set.opened);
319:         var it = set.blocks_released.iterator(.{
320:             .kind = .set,
321:             .direction = .reverse,
322:         });
323: 
324:         if (it.next()) |block| {
325:             const address = block + 1;
326:             return address;
327:         } else {
328:             assert(set.count_released() == 0);
329:             return null;
330:         }
331:     }
332: 
333:     /// Reserve `reserve_count` free blocks. The blocks are not acquired yet.
334:     ///
335:     /// Invariants:
336:     ///
337:     ///   - If a reservation is returned, it covers exactly `reserve_count` free blocks, along with
338:     ///     any interleaved already-acquired blocks.
339:     ///   - Active reservations are exclusive (i.e. disjoint).
340:     ///     (A reservation is active until `forfeit()` is called.)
341:     ///
342:     /// Returns null if there are not enough blocks free and vacant.
343:     /// Returns a reservation which can be used with `acquire()`:
344:     /// - The caller should consider the returned Reservation as opaque and immutable.
345:     /// - Each `reserve()` call which returns a non-null Reservation must correspond to exactly one
346:     ///   `forfeit()` call.
347:     pub fn reserve(set: *FreeSet, reserve_count: usize) ?Reservation {
348:         assert(set.opened);
349:         assert(set.reservation_state == .reserving);
350:         assert(reserve_count > 0);
351: 
352:         const shard_start = find_bit(
353:             set.index,
354:             @divFloor(set.reservation_blocks, shard_bits),
355:             set.index.bit_length,
356:             .unset,
357:         ) orelse return null;
358: 
359:         // The reservation may cover (and ignore) already-acquired blocks due to fragmentation.
360:         var block = @max(shard_start * shard_bits, set.reservation_blocks);
361:         for (0..reserve_count) |_| {
362:             block = 1 + (find_bit(
363:                 set.blocks_acquired,
364:                 block,
365:                 set.blocks_acquired.bit_length,
366:                 .unset,
367:             ) orelse return null);
368: 
369:             // The free block from the `blocks_acquired` bit set may be past the total number of
370:             // blocks that this free set is allowed to acquire (see `block_count_max`).
371:             if (block > set.blocks_count_limit) return null;
372:         }
373:         const block_base = set.reservation_blocks;
374:         const block_count = block - set.reservation_blocks;
375:         set.reservation_blocks += block_count;
376:         set.reservation_count += 1;
377: 
378:         return Reservation{
379:             .block_base = block_base,
380:             .block_count = block_count,
381:             .session = set.reservation_session,
382:         };
383:     }
384: 
385:     /// After invoking `forfeit()`, the reservation must never be used again.
386:     pub fn forfeit(set: *FreeSet, reservation: Reservation) void {
387:         assert(set.opened);
388:         assert(set.reservation_session == reservation.session);
389: 
390:         set.reservation_count -= 1;
391:         if (set.reservation_count == 0) {
392:             // All reservations have been dropped.
393:             set.reservation_blocks = 0;
394:             set.reservation_session +%= 1;
395:             set.reservation_state = .reserving;
396:         } else {
397:             set.reservation_state = .forfeiting;
398:         }
399:     }
400: 
401:     /// Marks a free block from the reservation as allocated, and returns the address.
402:     /// The reservation must not have been forfeited yet.
403:     /// The reservation must belong to the current cycle of reservations.
404:     ///
405:     /// Invariants:
406:     ///
407:     ///   - An acquired block cannot be acquired again until it has been released and the release
408:     ///     has been checkpointed.
409:     ///
410:     /// Returns null if no free block is available in the reservation.
411:     pub fn acquire(set: *FreeSet, reservation: Reservation) ?u64 {
412:         assert(set.opened);
413:         assert(set.reservation_count > 0);
414:         assert(reservation.block_count > 0);
415:         assert(reservation.block_base < set.reservation_blocks);
416:         assert(reservation.block_base + reservation.block_count <= set.reservation_blocks);
417:         assert(reservation.session == set.reservation_session);
418: 
419:         const shard_start = find_bit(
420:             set.index,
421:             @divFloor(reservation.block_base, shard_bits),
422:             div_ceil(reservation.block_base + reservation.block_count, shard_bits),
423:             .unset,
424:         ) orelse return null;
425:         assert(!set.index.isSet(shard_start));
426: 
427:         const reservation_start = @max(
428:             shard_start * shard_bits,
429:             reservation.block_base,
430:         );
431:         const reservation_end = reservation.block_base + reservation.block_count;
432:         const block = find_bit(
433:             set.blocks_acquired,
434:             reservation_start,
435:             reservation_end,
436:             .unset,
437:         ) orelse return null;
438:         assert(block >= reservation.block_base);
439:         assert(block <= reservation.block_base + reservation.block_count);
440:         assert(!set.blocks_acquired.isSet(block));
441:         assert(!set.blocks_released.isSet(block));
442:         assert(!set.blocks_released_prior_checkpoint_durability.contains(block));
443: 
444:         // Even if "shard_start" has free blocks, we might acquire our block from a later shard.
445:         // (This is possible because our reservation begins part-way through the shard.)
446:         const shard = @divFloor(block, shard_bits);
447:         maybe(shard == shard_start);
448:         assert(shard >= shard_start);
449: 
450:         set.blocks_acquired.set(block);
451:         // Update the index when every block in the shard is acquired.
452:         if (set.find_free_block_in_shard(shard) == null) set.index.set(shard);
453:         const address = block + 1;
454:         return address;
455:     }
456: 
457:     fn find_free_block_in_shard(set: FreeSet, shard: usize) ?usize {
458:         maybe(set.opened);
459:         const shard_start = shard * shard_bits;
460:         const shard_end = shard_start + shard_bits;
461:         assert(shard_start < set.blocks_acquired.bit_length);
462: 
463:         return find_bit(set.blocks_acquired, shard_start, shard_end, .unset);
464:     }
465: 
466:     pub fn is_free(set: FreeSet, address: u64) bool {
467:         if (set.opened) {
468:             const block = address - 1;
469:             return !set.blocks_acquired.isSet(block);
470:         } else {
471:             // When the free set is not open, conservatively assume that the block is acquired.
472:             //
473:             // This path is hit only when the replica opens the free set, reading its blocks from
474:             // the grid.
475:             return false;
476:         }
477:     }
478: 
479:     pub fn is_released(set: *const FreeSet, address: u64) bool {
480:         assert(set.opened);
481:         const block = address - 1;
482:         return set.blocks_released_prior_checkpoint_durability.contains(block) or
483:             set.blocks_released.isSet(block);
484:     }
485: 
486:     /// Returns `true` if the block at the given address would be freed when the current checkpoint
487:     /// becomes durable (when checkpoint_durable is set to `true`).
488:     ///
489:     /// Calling this function is only valid while the current checkpoint is not durable. During this
490:     /// period, blocks are marked as released in `blocks_released_prior_checkpoint_durability`;
491:     /// `blocks_released` remains unchanged and contains blocks released during the previous
492:     /// checkpoint interval.
493:     pub fn to_be_freed_at_checkpoint_durability(set: *const FreeSet, address: u64) bool {
494:         const block = address - 1;
495: 
496:         assert(set.opened);
497:         assert(!set.checkpoint_durable);
498: 
499:         // Block address must be acquired, but is not necessarily released.
500:         assert(set.blocks_acquired.isSet(block));
501:         assert(!set.blocks_released.isSet(block) or
502:             !set.blocks_released_prior_checkpoint_durability.contains(block));
503:         maybe(set.blocks_released.isSet(block));
504:         maybe(set.blocks_released_prior_checkpoint_durability.contains(block));
505: 
506:         return set.blocks_released.isSet(block);
507:     }
508: 
509:     /// Leave the address acquired for now, but free it when the next checkpoint becomes durable.
510:     /// This ensures that it will not be overwritten during the current checkpoint — the block may
511:     /// still be needed if we crash and recover from the current checkpoint.
512:     /// (TODO) If the block was created since the last checkpoint then it's safe to free
513:     ///        immediately. This may reduce space amplification, especially for smaller datasets.
514:     ///        (Note: This must be careful not to release while any reservations are held
515:     ///        to avoid making the reservation's acquire()s nondeterministic).
516:     pub fn release(set: *FreeSet, address: u64) void {
517:         assert(set.opened);
518: 
519:         const block = address - 1;
520:         assert(set.blocks_acquired.isSet(block));
521:         assert(!set.blocks_released.isSet(block));
522:         assert(!set.blocks_released_prior_checkpoint_durability.contains(block));
523: 
524:         // `blocks_released` remains unchanged while the current checkpoint is not durable,
525:         // since it contains blocks released in the previous checkpoint. These blocks must not be
526:         // freed till the current checkpoint is durable, so as to maintain the durability of these
527:         // blocks on a commit quorum of replicas.
528:         if (set.checkpoint_durable) {
529:             set.blocks_released.set(block);
530:         } else {
531:             set.blocks_released_prior_checkpoint_durability.putAssumeCapacity(block, {});
532:         }
533:     }
534: 
535:     /// Mark the given addresses as allocated in the current checkpoint, but free in the next one.
536:     ///
537:     /// This is used only when reading a free set from the grid. On disk representation of the
538:     /// free set doesn't include the blocks storing the free set itself, and these blocks must be
539:     /// manually patched in after decoding. As the next checkpoint will have a completely different
540:     /// free set, the blocks can be simultaneously released.
541:     fn mark_released(set: *FreeSet, addresses: []const u64) void {
542:         assert(!set.opened);
543:         assert(!set.checkpoint_durable);
544: 
545:         var address_previous: u64 = 0;
546:         for (addresses) |address| {
547:             assert(address > 0);
548: 
549:             // Assert that addresses are sorted and unique. Sortedness is not a requirement, but
550:             // a consequence of "first free" allocation algorithm.
551:             assert(address > address_previous);
552:             address_previous = address;
553: 
554:             const block = address - 1;
555: 
556:             assert(!set.blocks_acquired.isSet(block));
557:             assert(!set.blocks_released.isSet(block));
558:             assert(!set.blocks_released_prior_checkpoint_durability.contains(block));
559: 
560:             set.blocks_acquired.set(block);
561: 
562:             const shard = @divFloor(block, shard_bits);
563:             // Update the index when every block in the shard is acquired.
564:             if (set.find_free_block_in_shard(shard) == null) set.index.set(shard);
565: 
566:             set.blocks_released_prior_checkpoint_durability.putAssumeCapacity(block, {});
567:         }
568:     }
569: 
570:     /// Given the address, marks an acquired block as free.
571:     fn free(set: *FreeSet, address: u64) void {
572:         assert(set.opened);
573:         assert(set.checkpoint_durable);
574: 
575:         const block = address - 1;
576:         assert(set.blocks_acquired.isSet(block));
577:         assert(set.blocks_released.isSet(block));
578:         assert(!set.blocks_released_prior_checkpoint_durability.contains(block));
579: 
580:         assert(set.reservation_count == 0);
581:         assert(set.reservation_blocks == 0);
582: 
583:         set.index.unset(@divFloor(block, shard_bits));
584:         set.blocks_acquired.unset(block);
585:         set.blocks_released.unset(block);
586:     }
587: 
588:     pub fn mark_checkpoint_not_durable(set: *FreeSet) void {
589:         assert(set.opened);
590:         assert(set.checkpoint_durable);
591:         assert(set.blocks_released_prior_checkpoint_durability.count() == 0);
592:         set.checkpoint_durable = false;
593:     }
594: 
595:     /// Now that the checkpoint is durable on a commit quorum of replicas:
596:     /// 1. Mark the current checkpoint as durable.
597:     /// 2. Mark all released blocks in `blocks_released` as free.
598:     /// 3. Move released blocks from `blocks_released_prior_checkpoint_durability` to
599:     ///   `blocks_released`.
600:     pub fn mark_checkpoint_durable(set: *FreeSet) void {
601:         assert(set.opened);
602:         assert(!set.checkpoint_durable);
603: 
604:         set.checkpoint_durable = true;
605: 
606:         var it = set.blocks_released.iterator(.{ .kind = .set });
607:         while (it.next()) |block| set.free(block + 1);
608: 
609:         assert(set.blocks_released.count() == 0);
610: 
611:         // Block releases from the current checkpoint that were temporarily recorded in
612:         // blocks_released_prior_checkpoint_durability can now be moved to blocks_released.
613:         while (set.blocks_released_prior_checkpoint_durability.pop()) |block_entry| {
614:             const block = block_entry.key;
615:             set.blocks_released.set(block);
616:         }
617:         assert(set.blocks_released_prior_checkpoint_durability.count() == 0);
618: 
619:         // Index verification is O(blocks.bit_length) so do it only when checkpoint is marked
620:         // durable, which is also linear (as we free released blocks in `blocks_released`).
621:         set.verify_index();
622:     }
623: 
624:     /// Decodes the compressed bitset chunks in `source_chunks` into `target_bitset`.
625:     /// Panics if the `source_chunks` encoding is invalid.
626:     fn decode(
627:         set: *FreeSet,
628:         target_bitset: FreeSet.BitsetKind,
629:         source_chunks: []const []align(@alignOf(Word)) const u8,
630:     ) void {
631:         assert(!set.opened);
632:         assert(!set.checkpoint_durable);
633: 
634:         var source_size: usize = 0;
635: 
636:         for (source_chunks) |source_chunk| source_size += source_chunk.len;
637: 
638:         const target_bitset_words = switch (target_bitset) {
639:             .blocks_acquired => bit_set_masks(set.blocks_acquired),
640:             .blocks_released => bit_set_masks(set.blocks_released),
641:         };
642: 
643:         var decoder = ewah.decode_chunks(target_bitset_words, source_size);
644: 
645:         var words_decoded: usize = 0;
646:         for (source_chunks) |source_chunk| {
647:             words_decoded += decoder.decode_chunk(source_chunk);
648:         }
649:         assert(decoder.done());
650: 
651:         assert(@bitSizeOf(Word) == @bitSizeOf(MaskInt));
652:         assert(words_decoded * @bitSizeOf(Word) <= set.blocks_acquired.bit_length);
653: 
654:         // The encoder does not encode trailing 0s, so everything past words_decoded must be zeroed.
655:         assert(stdx.zeroed(std.mem.sliceAsBytes(target_bitset_words[words_decoded..])));
656:         // TODO: uncomment on the next release:
657:         // if (words_decoded > 0) assert(target_bitset_words[words_decoded - 1] != 0);
658:     }
659: 
660:     pub fn decode_chunks(
661:         set: *FreeSet,
662:         source_chunks_blocks_acquired: []const []align(@alignOf(Word)) const u8,
663:         source_chunks_blocks_released: []const []align(@alignOf(Word)) const u8,
664:     ) void {
665:         assert(!set.opened);
666:         assert(!set.checkpoint_durable);
667: 
668:         // Verify that this FreeSet is entirely unallocated.
669:         assert(set.index.count() == 0);
670:         assert(set.blocks_acquired.count() == 0);
671:         assert(set.blocks_released.count() == 0);
672:         assert(set.blocks_released_prior_checkpoint_durability.count() == 0);
673: 
674:         assert(set.reservation_count == 0);
675:         assert(set.reservation_blocks == 0);
676: 
677:         set.decode(.blocks_acquired, source_chunks_blocks_acquired);
678:         set.decode(.blocks_released, source_chunks_blocks_released);
679: 
680:         for (0..set.index.bit_length) |shard| {
681:             if (set.find_free_block_in_shard(shard) == null) set.index.set(shard);
682:         }
683: 
684:         set.verify_index();
685:     }
686: 
687:     /// Returns the number of blocks that the free set can physically reference via the acquired
688:     /// and released bitsets. Logically, the limit on the number of blocks that can be acquired by
689:     /// the free set is imposed by --limit-storage.
690:     pub fn block_count_max(grid_size_limit: usize) usize {
691:         const block_count_limit = @divFloor(grid_size_limit, constants.block_size);
692:         return stdx.div_ceil(block_count_limit, shard_bits) * shard_bits;
693:     }
694: 
695:     /// Returns the maximum number of bytes needed for encoding the acquired/released bitset.
696:     pub fn encode_size_max(set: *const FreeSet) usize {
697:         assert(set.blocks_acquired.bit_length == set.blocks_released.bit_length);
698: 
699:         const blocks_count = set.blocks_acquired.bit_length;
700:         assert(blocks_count % shard_bits == 0);
701:         assert(blocks_count % @bitSizeOf(usize) == 0);
702: 
703:         return ewah.encode_size_max(@divExact(blocks_count, @bitSizeOf(Word)));
704:     }
705: 
706:     fn encode(
707:         set: *const FreeSet,
708:         source_bitset: FreeSet.BitsetKind,
709:         target_chunks: []const []align(@alignOf(Word)) u8,
710:     ) usize {
711:         assert(set.opened);
712:         assert(set.checkpoint_durable);
713: 
714:         var encoder = switch (source_bitset) {
715:             .blocks_acquired => ewah.encode_chunks(bit_set_masks(set.blocks_acquired)),
716:             .blocks_released => ewah.encode_chunks(bit_set_masks(set.blocks_released)),
717:         };
718:         defer assert(encoder.done());
719: 
720:         var bytes_encoded_total: u64 = 0;
721:         for (target_chunks) |chunk| {
722:             const bytes_encoded =
723:                 @as(u32, @intCast(encoder.encode_chunk(chunk)));
724:             assert(bytes_encoded > 0);
725: 
726:             bytes_encoded_total += bytes_encoded;
727: 
728:             if (encoder.done()) break;
729:         } else unreachable;
730: 
731:         // Don't explicitly encode trailing zeros to ensure that the encoding is the same regardless
732:         // of the runtime-configurable capacity of the bit set (driven by --limit-storage).
733:         const bytes_trailing_zero_runs = encoder.trailing_zero_runs_count * @sizeOf(ewah.Marker);
734: 
735:         return bytes_encoded_total - bytes_trailing_zero_runs;
736:     }
737: 
738:     pub fn encode_chunks(
739:         set: *const FreeSet,
740:         target_chunks_blocks_acquired: []const []align(@alignOf(Word)) u8,
741:         target_chunks_blocks_released: []const []align(@alignOf(Word)) u8,
742:     ) struct { encoded_size_blocks_acquired: u64, encoded_size_blocks_released: u64 } {
743:         assert(set.opened);
744:         assert(set.checkpoint_durable);
745:         assert(set.reservation_count == 0);
746:         assert(set.reservation_blocks == 0);
747: 
748:         return .{
749:             .encoded_size_blocks_acquired = set.encode(
750:                 .blocks_acquired,
751:                 target_chunks_blocks_acquired,
752:             ),
753:             .encoded_size_blocks_released = set.encode(
754:                 .blocks_released,
755:                 target_chunks_blocks_released,
756:             ),
757:         };
758:     }
759: };
760: 
761: fn bit_set_masks(bit_set: DynamicBitSetUnmanaged) []MaskInt {
762:     const len = div_ceil(bit_set.bit_length, @bitSizeOf(MaskInt));
763:     return bit_set.masks[0..len];
764: }
