933:     defer set.deinit(gpa);
934: 
935:     var empty = try FreeSet.open_empty(gpa, blocks_count);
936:     defer empty.deinit(gpa);
937: 
938:     var full = try FreeSet.open_empty(gpa, blocks_count);
939:     defer full.deinit(gpa);
940: 
941:     {
942:         // Acquire all of `full`'s blocks.
943:         const reservation = full.reserve(blocks_count).?;
944:         defer full.forfeit(reservation);
945: 
946:         for (0..full.blocks_acquired.bit_length) |i| {
947:             try expectEqual(@as(?u64, i + 1), full.acquire(reservation));
948:         }
949:     }
950: 
951:     {
952:         // Acquire & stage-release every block.
953:         const reservation = set.reserve(blocks_count).?;
954:         defer set.forfeit(reservation);
955: 
956:         for (0..set.blocks_acquired.bit_length) |i| {
957:             try expectEqual(@as(?u64, i + 1), set.acquire(reservation));
958:             set.release(i + 1);
959: 
960:             // These count functions treat staged blocks as acquired.
961:             try expectEqual(@as(u64, i + 1), set.count_acquired());
962:             try expectEqual(@as(u64, set.blocks_acquired.bit_length - i - 1), set.count_free());
963:         }
964:         // All blocks are still acquired, though staged to release at the next checkpoint.
965:         try expectEqual(@as(?u64, null), set.acquire(reservation));
966:     }
967: 
968:     // Perform checkpoint-related operations.
969:     set.mark_checkpoint_not_durable();
970:     set.mark_checkpoint_durable();
971: 
972:     try expect_free_set_equal(empty, set);
973:     try expectEqual(@as(usize, 0), set.blocks_released.count());
974: 
975:     {
976:         // Allocate & stage-release all blocks again.
977:         const reservation = set.reserve(blocks_count).?;
978:         defer set.forfeit(reservation);
979: 
980:         for (0..set.blocks_acquired.bit_length) |i| {
981:             try expectEqual(@as(?u64, i + 1), set.acquire(reservation));
982:             set.release(i + 1);
983:         }
984:     }
985: 
986:     const set_encoded_blocks_acquired = try gpa.alignedAlloc(
987:         u8,
988:         @alignOf(FreeSet.Word),
989:         set.encode_size_max(),
990:     );
991:     const set_encoded_blocks_released = try gpa.alignedAlloc(
992:         u8,
993:         @alignOf(FreeSet.Word),
994:         set.encode_size_max(),
995:     );
996: 
997:     defer gpa.free(set_encoded_blocks_acquired);
998:     defer gpa.free(set_encoded_blocks_released);
999: 
1000:     var set_decoded = try FreeSet.init_empty(gpa, blocks_count);
