1032: test "FreeSet encode, decode, encode" {
1033:     const shard_bits = FreeSet.shard_bits / @bitSizeOf(usize);
1034:     const gpa = std.testing.allocator;
1035: 
1036:     // Uniform.
1037:     try test_encode(&.{.{ .fill = .uniform_ones, .words = shard_bits }});
1038:     try test_encode(&.{.{ .fill = .uniform_zeros, .words = shard_bits }});
1039:     try test_encode(&.{.{ .fill = .literal, .words = shard_bits }});
1040:     try test_encode(&.{.{ .fill = .uniform_ones, .words = std.math.maxInt(u16) + 1 }});
1041: 
1042:     // Mixed.
1043:     try test_encode(&.{
1044:         .{ .fill = .uniform_ones, .words = shard_bits / 4 },
1045:         .{ .fill = .uniform_zeros, .words = shard_bits / 4 },
1046:         .{ .fill = .literal, .words = shard_bits / 4 },
1047:         .{ .fill = .uniform_ones, .words = shard_bits / 4 },
1048:     });
1049: 
1050:     // Random.
1051:     const seed = std.crypto.random.int(u64);
1052:     var prng = stdx.PRNG.from_seed(seed);
1053: 
1054:     const fills = [_]TestPatternFill{ .uniform_ones, .uniform_zeros, .literal };
1055:     for (0..10) |_| {
1056:         var patterns = std.ArrayList(TestPattern).init(gpa);
1057:         defer patterns.deinit();
1058: 
1059:         for (0..shard_bits) |_| {
1060:             try patterns.append(.{
1061:                 .fill = fills[prng.index(fills)],
1062:                 .words = 1,
1063:             });
1064:         }
1065:         try test_encode(patterns.items);
1066:     }
1067: }
1068: 
1069: const TestPattern = struct {
1070:     fill: TestPatternFill,
1071:     words: usize,
1072: };
1073: 
1074: const TestPatternFill = enum { uniform_ones, uniform_zeros, literal };
1075: 
1076: fn test_encode(patterns: []const TestPattern) !void {
1077:     const gpa = std.testing.allocator;
1078:     const seed = std.crypto.random.int(u64);
1079:     var prng = stdx.PRNG.from_seed(seed);
1080: 
1081:     var blocks_count: usize = 0;
1082:     for (patterns) |pattern| blocks_count += pattern.words * @bitSizeOf(usize);
1083: 
1084:     var decoded_expect = try FreeSet.open_empty(gpa, blocks_count);
1085:     defer decoded_expect.deinit(gpa);
1086: 
1087:     {
1088:         // The `index` will start out one-filled. Every pattern containing a zero will update the
1089:         // corresponding index bit with a zero (probably multiple times) to ensure it ends up synced
1090:         // with `blocks`.
1091:         decoded_expect.index.toggleAll();
1092:         assert(decoded_expect.index.count() == decoded_expect.index.capacity());
1093: 
1094:         // Fill the bitset according to the patterns.
1095:         var blocks = bit_set_masks(decoded_expect.blocks_acquired);
1096:         var blocks_offset: usize = 0;
1097:         for (patterns) |pattern| {
1098:             for (0..pattern.words) |_| {
1099:                 blocks[blocks_offset] = switch (pattern.fill) {
1100:                     .uniform_ones => ~@as(usize, 0),
1101:                     .uniform_zeros => 0,
1102:                     .literal => prng.range_inclusive(usize, 1, std.math.maxInt(usize) - 1),
1103:                 };
1104:                 const index_bit = blocks_offset * @bitSizeOf(usize) / FreeSet.shard_bits;
1105:                 if (pattern.fill != .uniform_ones) decoded_expect.index.unset(index_bit);
1106:                 blocks_offset += 1;
1107:             }
1108:         }
1109:         assert(blocks_offset == blocks.len);
1110:     }
1111: 
1112:     var encoded = try gpa.alignedAlloc(
1113:         u8,
1114:         @alignOf(FreeSet.Word),
1115:         decoded_expect.encode_size_max(),
1116:     );
1117:     defer gpa.free(encoded);
1118: 
1119:     try std.testing.expectEqual(encoded.len % 8, 0);
1120:     const encoded_length = decoded_expect.encode(.blocks_acquired, &.{encoded});
1121: 
1122:     var decoded_actual = try FreeSet.init_empty(gpa, blocks_count);
1123:     defer decoded_actual.deinit(gpa);
1124: 
1125:     decoded_actual.decode_chunks(&.{encoded[0..encoded_length]}, &.{});
1126:     try expect_free_set_equal(decoded_expect, decoded_actual);
1127: }
