1246: /// Returns the index of the first set/unset bit (relative to the start of the bitset) within
1247: /// the range bit_min…bit_max (inclusive…exclusive).
1248: fn find_bit(
1249:     bit_set: DynamicBitSetUnmanaged,
1250:     bit_min: usize,
1251:     bit_max: usize,
1252:     comptime bit_kind: std.bit_set.IteratorOptions.Type,
1253: ) ?usize {
1254:     assert(bit_max >= bit_min);
1255:     assert(bit_max <= bit_set.bit_length);
1256: 
1257:     const word_start = @divFloor(bit_min, @bitSizeOf(MaskInt)); // Inclusive.
1258:     const word_offset = @mod(bit_min, @bitSizeOf(MaskInt));
1259:     const word_end = div_ceil(bit_max, @bitSizeOf(MaskInt)); // Exclusive.
1260:     const words_total = div_ceil(bit_set.bit_length, @bitSizeOf(MaskInt));
1261:     if (word_end == word_start) return null;
1262:     assert(word_end > word_start);
1263: 
1264:     // Only iterate over the subset of bits that were requested.
1265:     var iterator = bit_set.iterator(.{ .kind = bit_kind });
1266:     iterator.words_remain = bit_set.masks[word_start + 1 .. word_end];
1267: 
1268:     const mask = ~@as(MaskInt, 0);
1269:     var word = bit_set.masks[word_start];
1270:     if (bit_kind == .unset) word = ~word;
1271:     iterator.bits_remain = word & std.math.shl(MaskInt, mask, word_offset);
1272: 
1273:     if (word_end != words_total) iterator.last_word_mask = mask;
1274: 
1275:     const b = bit_min - word_offset + (iterator.next() orelse return null);
1276:     return if (b < bit_max) b else null;
1277: }
