1296: fn test_find_bit(
1297:     prng: *stdx.PRNG,
1298:     bit_set: DynamicBitSetUnmanaged,
1299:     comptime bit_kind: std.bit_set.IteratorOptions.Type,
1300: ) !void {
1301:     const bit_min = prng.int_inclusive(usize, bit_set.bit_length - 1);
1302:     const bit_max = prng.range_inclusive(usize, bit_min, bit_set.bit_length);
1303:     assert(bit_max >= bit_min);
1304:     assert(bit_max <= bit_set.bit_length);
1305: 
1306:     const bit_actual = find_bit(bit_set, bit_min, bit_max, bit_kind);
1307:     if (bit_actual) |bit| {
1308:         assert(bit_set.isSet(bit) == (bit_kind == .set));
1309:         assert(bit >= bit_min);
1310:         assert(bit < bit_max);
1311:     }
1312: 
1313:     var iterator = bit_set.iterator(.{ .kind = bit_kind });
1314:     while (iterator.next()) |bit| {
1315:         if (bit_min <= bit and bit < bit_max) {
1316:             try std.testing.expectEqual(bit_actual, bit);
1317:             break;
1318:         }
1319:     } else {
1320:         try std.testing.expectEqual(bit_actual, null);
1321:     }
1322: }
