1: //! Convenient constructs for TigerBeetle components, for fuzzing and testing.
2: //!
3: //! Consider the Grid. In the actual database, there is only single call to Grid.init.
4: //! However, Grid is needed for most of our tests and fuzzers. If the init call is repeated
5: //! in every fuzzer, changing Storage creation flow becomes hard. To solve this, all fuzzers create
6: //! Grid through this file, such that we have one production and one test call to Grid.init.
7: //!
8: //! Design:
9: //!
10: //! - All functions take struct options as a last argument, even if it starts out as empty.
11: //!   All call-sites pass at least .{}, which makes adding new options cheap.
12: //! - Most options should have defaults. This is intentional deviation from TigerStyle, as, for
13: //!   tests, we gain a useful property: all options that are set are meaningful for a particular
14: //!   test.
15: //! - All dependent fixtures are passed in positionally because they can't be defaulted and their
16: //!   types are unique.
17: //! - It could be convenient to export types themselves, in addition to constructors, but we avoid
18: //!   introducing two ways to import something.
19: const std = @import("std");
20: const vsr = @import("../vsr.zig");
21: const constants = @import("../constants.zig");
22: const assert = std.debug.assert;
23: 
24: const Time = @import("../time.zig").Time;
25: const OffsetType = @import("./time.zig").OffsetType;
26: const Tracer = @import("../trace.zig").Tracer;
27: const Storage = @import("./storage.zig").Storage;
28: const SuperBlock = vsr.SuperBlockType(Storage);
29: const Grid = vsr.GridType(Storage);
30: 
31: const TimeSim = @import("./time.zig").TimeSim;
32: 
33: pub const cluster: u128 = 0;
34: pub const replica: u8 = 0;
35: pub const replica_count: u8 = 6;
36: 
37: pub fn init_time(options: struct {
38:     resolution: u64 = constants.tick_ms * std.time.ns_per_ms,
39:     offset_type: OffsetType = .linear,
40:     offset_coefficient_A: i64 = 0,
41:     offset_coefficient_B: i64 = 0,
42:     offset_coefficient_C: u32 = 0,
43: }) TimeSim {
44:     const result: TimeSim = .{
45:         .resolution = options.resolution,
46:         .offset_type = options.offset_type,
47:         .offset_coefficient_A = options.offset_coefficient_A,
48:         .offset_coefficient_B = options.offset_coefficient_B,
49:         .offset_coefficient_C = options.offset_coefficient_C,
50:     };
51:     return result;
52: }
