54: pub fn init_tracer(gpa: std.mem.Allocator, init: Time, options: struct {
55:     writer: ?std.io.AnyWriter = null,
56:     process_id: Tracer.ProcessID = .{ .replica = .{ .cluster = cluster, .replica = replica } },
57: }) !Tracer {
58:     return Tracer.init(gpa, init, options.process_id, .{ .writer = options.writer });
59: }
