61: pub fn init_storage(gpa: std.mem.Allocator, options: Storage.Options) !Storage {
62:     return try Storage.init(gpa, options);
63: }
64: 
65: pub fn storage_format(
66:     gpa: std.mem.Allocator,
67:     storage: *Storage,
68:     options: struct {
69:         cluster: u128 = cluster,
70:         replica: u8 = replica,
71:         replica_count: u8 = replica_count,
72:         release: vsr.Release = vsr.Release.minimum,
73:     },
74: ) !void {
75:     assert(storage.reads.count() == 0);
76:     assert(storage.writes.count() == 0);
77: 
78:     var superblock = try init_superblock(gpa, storage, .{});
79:     defer superblock.deinit(gpa);
80: 
81:     const Context = struct {
82:         superblock_context: SuperBlock.Context = undefined,
83:         done: bool = false,
84:         fn callback(superblock_context: *SuperBlock.Context) void {
85:             const self: *@This() = @fieldParentPtr("superblock_context", superblock_context);
86:             assert(!self.done);
87:             self.done = true;
88:         }
89:     };
90:     var context: Context = .{};
91: 
92:     superblock.format(Context.callback, &context.superblock_context, .{
93:         .cluster = options.cluster,
94:         .replica = options.replica,
95:         .replica_count = options.replica_count,
96:         .release = options.release,
97:         .view = null,
98:     });
99:     for (0..10_000) |_| {
100:         if (context.done) break;
101:         storage.run();
102:     } else @panic("superblock format loop stuck");
103:     assert(storage.reads.count() == 0);
104:     assert(storage.writes.count() == 0);
105: }
