118:     blocks_released_prior_checkpoint_durability_max: u64 = 0,
119: }) !Grid {
120:     return try Grid.init(gpa, .{
121:         .superblock = superblock,
122:         .trace = trace,
123:         .missing_blocks_max = options.missing_blocks_max,
124:         .missing_tables_max = options.missing_tables_max,
125:         .blocks_released_prior_checkpoint_durability_max = //
126:         options.blocks_released_prior_checkpoint_durability_max,
127:     });
128: }
