130: pub fn open_superblock(superblock: *SuperBlock) void {
131:     const storage: *Storage = superblock.storage;
132:     assert(storage.reads.count() == 0);
133:     assert(storage.writes.count() == 0);
134:     defer assert(storage.reads.count() == 0);
135:     defer assert(storage.writes.count() == 0);
136: 
137:     const Context = struct {
138:         superblock_context: SuperBlock.Context = undefined,
139:         pending: bool = false,
140: 
141:         fn callback(superblock_context: *SuperBlock.Context) void {
142:             const self: *@This() = @fieldParentPtr("superblock_context", superblock_context);
143:             assert(self.pending);
144:             self.pending = false;
145:         }
146:     };
147:     var context: Context = .{};
148: 
149:     context.pending = true;
150:     superblock.open(Context.callback, &context.superblock_context);
151:     for (0..10_000) |_| {
152:         storage.run();
153:         if (!context.pending) break;
154:     } else @panic("open superblock stuck");
155: }
156: 
157: pub fn open_grid(grid: *Grid) void {
158:     const storage: *Storage = grid.superblock.storage;
159:     assert(storage.reads.count() == 0);
160:     assert(storage.writes.count() == 0);
161:     defer assert(storage.reads.count() == 0);
162:     defer assert(storage.writes.count() == 0);
163: 
164:     const Context = struct {
165:         pending: bool = false,
166:         // NB: This lacks in elegance and robustness, but is good enough for testing.
167:         var global: @This() = .{};
168:         fn callback(_: *Grid) void {
169:             assert(@This().global.pending);
170:             @This().global.pending = false;
171:         }
172:     };
173: 
174:     assert(!Context.global.pending);
175:     Context.global.pending = true;
176:     grid.open(Context.callback);
177:     for (0..10_000) |_| {
178:         storage.run();
179:         if (!Context.global.pending) break;
180:     } else @panic("open grid stuck");
181: }
