1: const std = @import("std");
2: const stdx = @import("stdx");
3: const assert = std.debug.assert;
4: 
5: const constants = @import("../constants.zig");
6: 
7: const ProcessID = @import("../trace.zig").ProcessID;
8: const IO = @import("../io.zig").IO;
9: 
10: const EventMetric = @import("event.zig").EventMetric;
11: const EventMetricAggregate = @import("event.zig").EventMetricAggregate;
12: const EventTiming = @import("event.zig").EventTiming;
13: const EventTimingAggregate = @import("event.zig").EventTimingAggregate;
14: 
15: const log = std.log.scoped(.statsd);
16: 
17: /// A reasonable value to keep the total length of the packet under a single MTU, for a local
18: /// network.
19: ///
20: /// https://github.com/statsd/statsd/blob/master/docs/metric_types.md#multi-metric-packets
21: const packet_size_max = 1400;
22: 
23: /// No single metric may be larger than this value. If it is, it'll be dropped with an error
24: /// message. Since this is calculated at comptime, that means there's a bug in the calculation
25: /// logic.
26: const statsd_line_size_max = line_size_max: {
27:     // For each type of event, build a payload containing the maximum possible values for that
28:     // event. This is essentially maxInt for unsigned integer payloads, minInt for signed integer
29:     // payloads, and the longest enum tag name for enum payloads.
30:     var events_metric: [std.meta.fieldNames(EventMetric).len]EventMetricAggregate = undefined;
31:     for (&events_metric, std.meta.fields(EventMetric)) |*event_metric, EventMetricInner| {
32:         event_metric.* = .{
33:             .event = @unionInit(
34:                 EventMetric,
35:                 EventMetricInner.name,
36:                 struct_size_max(EventMetricInner.type),
37:             ),
38:             .value = if (@typeInfo(EventMetricAggregate.ValueType).int.signedness == .signed)
39:                 std.math.minInt(EventMetricAggregate.ValueType)
40:             else
41:                 std.math.maxInt(EventMetricAggregate.ValueType),
42:         };
43:     }
44: 
45:     var events_timing: [std.meta.fieldNames(EventTiming).len]EventTimingAggregate = undefined;
46:     for (&events_timing, std.meta.fields(EventTiming)) |*event_timing, EventTimingInner| {
47:         event_timing.* = .{
48:             .event = @unionInit(
49:                 EventTiming,
50:                 EventTimingInner.name,
51:                 struct_size_max(EventTimingInner.type),
52:             ),
53:             .values = .{
54:                 .duration_min = .{ .ns = std.math.maxInt(u64) },
55:                 .duration_max = .{ .ns = std.math.maxInt(u64) },
56:                 .duration_sum = .{ .ns = std.math.maxInt(u64) },
57:                 .count = std.math.maxInt(u64),
58:             },
59:         };
60:     }
61: 
62:     var buffer: [packet_size_max]u8 = undefined;
63:     var buffer_stream = std.io.fixedBufferStream(&buffer);
64:     const buffer_writer = buffer_stream.writer();
65: 
66:     var line_size_max: u32 = 0;
67:     for (events_metric) |event| {
68:         buffer_stream.reset();
69:         format_metric(
70:             buffer_writer,
71:             .{ .metric = .{ .aggregate = event } },
72:             .{ .cluster = std.math.maxInt(u128), .replica = constants.members_max - 1 },
73:         ) catch unreachable;
74:         line_size_max = @max(line_size_max, buffer_stream.getPos() catch unreachable);
75:     }
76:     for (events_timing) |event| {
77:         for (std.enums.values(TimingStat)) |stat| {
78:             buffer_stream.reset();
79:             format_metric(
80:                 buffer_writer,
81:                 .{ .timing = .{ .aggregate = event, .stat = stat } },
82:                 .{ .cluster = std.math.maxInt(u128), .replica = constants.members_max - 1 },
83:             ) catch unreachable;
84:             line_size_max = @max(line_size_max, buffer_stream.getPos() catch unreachable);
85:         }
86:     }
87:     break :line_size_max line_size_max;
88: };
89: 
90: const packet_messages_max = @divFloor(packet_size_max, statsd_line_size_max);
91: 
92: comptime {
93:     assert(statsd_line_size_max <= packet_size_max);
94:     assert(packet_messages_max > 0);
95: }
96: 
97: /// This implementation emits on an open-loop: on the emit interval, it fires off up to
98: /// packet_count_max UDP packets, without waiting for completions.
99: ///
100: /// The emit interval needs to be large enough that the kernel will have finished processing them
101: /// before emitting again. If not, an error will be logged.
102: const packet_count_max = stdx.div_ceil(
103:     EventMetric.slot_count + (EventTiming.slot_count * std.enums.values(TimingStat).len),
104:     packet_messages_max,
105: );
106: 
107: comptime {
108:     // Sanity-check:
109:     assert(packet_count_max > 0);
110:     assert(packet_count_max < 512);
111: }
112: 
113: pub const StatsD = struct {
114:     process_id: ProcessID,
115:     implementation: union(enum) {
116:         udp: struct {
117:             socket: std.posix.socket_t,
118:             io: *IO,
119:             send_callback_error_count: u64 = 0,
120:         },
121:         log,
122:     },
123: 
124:     send_buffer: *[packet_count_max * packet_size_max]u8,
125:     send_completions: [packet_count_max]IO.Completion = undefined,
126:     send_in_flight_count: u32 = 0,
127: 
128:     log_buffer: ?std.ArrayListUnmanaged(u8) = null,
129: 
130:     /// Creates a statsd instance, which will send UDP packets via the IO instance provided.
131:     pub fn init_udp(
132:         allocator: std.mem.Allocator,
133:         process_id: ProcessID,
134:         io: *IO,
135:         address: std.net.Address,
136:     ) !StatsD {
137:         const socket = try io.open_socket_udp(address.any.family);
138:         errdefer io.close_socket(socket);
139: 
140:         const send_buffer = try allocator.create([packet_count_max * packet_size_max]u8);
141:         errdefer allocator.destroy(send_buffer);
142: 
143:         // 'Connect' the UDP socket, so we can just send() to it normally.
144:         try std.posix.connect(socket, &address.any, address.getOsSockLen());
145: 
146:         log.info("{}: sending statsd metrics to {}", .{ process_id, address });
147: 
148:         return .{
149:             .process_id = process_id,
150:             .implementation = .{
151:                 .udp = .{
152:                     .socket = socket,
153:                     .io = io,
154:                 },
155:             },
156:             .send_buffer = send_buffer,
157:         };
158:     }
159: 
160:     // Creates a statsd instance, which will log out the packets that would have been sent. Useful
161:     // so that all of the other code can run and be tested in the simulator.
162:     pub fn init_log(
163:         allocator: std.mem.Allocator,
164:         process_id: ProcessID,
165:     ) !StatsD {
166:         const send_buffer = try allocator.create([packet_count_max * packet_size_max]u8);
167:         errdefer allocator.destroy(send_buffer);
168: 
169:         const log_buffer = try std.ArrayListUnmanaged(u8).initCapacity(
170:             allocator,
171:             packet_count_max * packet_size_max,
172:         );
173:         errdefer log_buffer.deinit(allocator);
174: 
175:         return .{
176:             .process_id = process_id,
177:             .implementation = .log,
178:             .send_buffer = send_buffer,
179:             .log_buffer = log_buffer,
180:         };
181:     }
182: 
183:     pub fn deinit(self: *StatsD, allocator: std.mem.Allocator) void {
184:         if (self.implementation == .udp) {
185:             self.implementation.udp.io.close_socket(self.implementation.udp.socket);
186:         }
187: 
188:         if (self.log_buffer) |*log_buffer| {
189:             log_buffer.deinit(allocator);
190:         }
191: 
192:         allocator.destroy(self.send_buffer);
193: 
194:         self.* = undefined;
195:     }
196: 
197:     pub fn emit(
198:         self: *StatsD,
199:         events_metric: []const ?EventMetricAggregate,
200:         events_timing: []const ?EventTimingAggregate,
201:     ) error{ Busy, UnknownProcess }!u32 {
202:         const cluster, const replica = switch (self.process_id) {
203:             .unknown => {
204:                 log.err("{}: process id unknown; skipping emit", .{self.process_id});
205:                 return error.UnknownProcess;
206:             },
207:             .replica => |replica| .{ replica.cluster, replica.replica },
208:         };
209: 
210:         // This really should not happen; it means we're emitting so many packets, on a short
211:         // enough emit timeout, that the kernel hasn't been able to process them all (UDP doesn't
212:         // block or provide back-pressure like a TCP socket).
213:         //
214:         // Keep it as a log, rather than assert, to avoid the common pitfall of metrics killing
215:         // the whole system.
216:         //
217:         // This is also a load-bearing check: see send_callback().
218:         if (self.send_in_flight_count != 0) {
219:             log.err("{}: {} / {} packets still in flight; skipping emit", .{
220:                 self.process_id,
221:                 self.send_in_flight_count,
222:                 packet_count_max,
223:             });
224:             return error.Busy;
225:         }
226: 
227:         // If there's a log buffer, clear it out before starting to emit.
228:         if (self.log_buffer) |*log_buffer| {
229:             log_buffer.clearRetainingCapacity();
230:         }
231: 
232:         if (self.implementation == .udp and self.implementation.udp.send_callback_error_count > 0) {
233:             log.warn(
234:                 "{}: failed to send {} packets",
235:                 .{ self.process_id, self.implementation.udp.send_callback_error_count },
236:             );
237:             self.implementation.udp.send_callback_error_count = 0;
238:         }
239: 
240:         var send_ready: u32 = 0;
241:         var send_sizes = stdx.BoundedArrayType(u32, packet_count_max){};
242:         var send_stream = std.io.fixedBufferStream(self.send_buffer);
243:         const send_writer = send_stream.writer();
244:         inline for (.{ events_metric, events_timing }) |events| {
245:             for (events) |event_new_maybe| {
246:                 const event_new = event_new_maybe orelse continue;
247:                 const stats = switch (@TypeOf(event_new)) {
248:                     EventMetricAggregate => [_]Stat{.{ .metric = .{ .aggregate = event_new } }},
249:                     EventTimingAggregate => [_]Stat{
250:                         .{ .timing = .{ .aggregate = event_new, .stat = .min } },
251:                         .{ .timing = .{ .aggregate = event_new, .stat = .max } },
252:                         .{ .timing = .{ .aggregate = event_new, .stat = .avg } },
253:                         .{ .timing = .{ .aggregate = event_new, .stat = .sum } },
254:                         .{ .timing = .{ .aggregate = event_new, .stat = .count } },
255:                     },
256:                     else => unreachable,
257:                 };
258: 
259:                 for (stats) |stat| {
260:                     const send_position_before = send_stream.getPos() catch unreachable;
261:                     format_metric(send_writer, stat, .{
262:                         .cluster = cluster,
263:                         .replica = replica,
264:                     }) catch |err| switch (err) {
265:                         // This shouldn't ever happen, but don't allow metrics to kill the system.
266:                         error.NoSpaceLeft => {
267:                             log.err("{}: insufficient buffer space", .{self.process_id});
268:                             break;
269:                         },
270:                     };
271: 
272:                     const send_position_after = send_stream.getPos() catch unreachable;
273:                     const send_size: u32 = @intCast(send_position_after - send_position_before);
274:                     assert(send_size > 0);
275:                     if (send_ready + send_size > packet_size_max) {
276:                         assert(send_ready > 0);
277:                         if (send_sizes.full()) {
278:                             log.err("{}: insufficient packet count", .{self.process_id});
279:                             break;
280:                         } else {
281:                             send_sizes.push(send_ready);
282:                         }
283:                         send_ready = send_size;
284:                     } else {
285:                         send_ready += send_size;
286:                     }
287:                 }
288:             }
289:         }
290:         if (send_ready > 0) {
291:             if (send_sizes.full()) {
292:                 log.err("{}: insufficient packet count", .{self.process_id});
293:             } else {
294:                 send_sizes.push(send_ready);
295:             }
296:         }
297: 
298:         var send_offset: u32 = 0;
299:         for (send_sizes.const_slice()) |send_size| {
300:             if (self.send_in_flight_count >= self.send_completions.len) {
301:                 // This shouldn't ever happen, but don't allow metrics to kill the system.
302:                 log.err("{}: insufficient packets to emit any metrics", .{self.process_id});
303:                 return 0;
304:             }
305:             const completion = &self.send_completions[self.send_in_flight_count];
306:             self.send_in_flight_count += 1;
307:             self.emit_buffer(completion, self.send_buffer[send_offset..][0..send_size]);
308:             send_offset += send_size;
309:         }
310: 
311:         return @intCast(send_sizes.count());
312:     }
313: 
314:     fn emit_buffer(self: *StatsD, send_completion: *IO.Completion, send_buffer: []const u8) void {
315:         switch (self.implementation) {
316:             .udp => |udp| {
317:                 udp.io.send(
318:                     *StatsD,
319:                     self,
320:                     StatsD.send_callback,
321:                     send_completion,
322:                     udp.socket,
323:                     send_buffer,
324:                 );
325:             },
326:             .log => {
327:                 self.log_buffer.?.appendSliceAssumeCapacity(send_buffer);
328:                 StatsD.send_callback(self, send_completion, send_buffer.len);
329:             },
330:         }
331:     }
332: 
333:     /// The UDP packets containing the metrics are sent in a fire-and-forget manner.
334:     fn send_callback(self: *StatsD, completion: *IO.Completion, result: IO.SendError!usize) void {
335:         _ = result catch {
336:             // Errors are only supported when using UDP; not if calling this loopback.
337:             assert(self.implementation == .udp);
338:             self.implementation.udp.send_callback_error_count += 1;
339:         };
340: 
341:         // Completions can be returned in any order: this is _only_ safe because their emitting is
342:         // guarded on `self.send_in_flight_count != 0`.
343:         self.send_in_flight_count -= 1;
344:         completion.* = undefined;
345:     }
346: };
347: 
348: const TimingStat = enum { min, max, avg, sum, count };
349: const Stat = union(enum) {
350:     metric: struct { aggregate: EventMetricAggregate },
351:     timing: struct { aggregate: EventTimingAggregate, stat: TimingStat },
352: };
353: 
354: fn format_metric(
355:     writer: anytype,
356:     stat: Stat,
357:     options: struct { cluster: u128, replica: u8 },
358: ) error{NoSpaceLeft}!void {
359:     const stat_name = switch (stat) {
360:         inline else => |stat_data| @tagName(stat_data.aggregate.event),
361:     };
362: 
363:     const stat_suffix, const stat_type, const stat_value = switch (stat) {
364:         .metric => |data| .{ "", "g", data.aggregate.value },
365:         .timing => |data| switch (data.stat) {
366:             .count => .{ "_us.count", "c", data.aggregate.values.count },
367:             .sum => .{ "_us.sum", "c", data.aggregate.values.duration_sum.to_us() },
368:             .min => .{ "_us.min", "g", data.aggregate.values.duration_min.to_us() },
369:             .max => .{ "_us.max", "g", data.aggregate.values.duration_max.to_us() },
370:             .avg => .{ "_us.avg", "g", @divFloor(
371:                 data.aggregate.values.duration_sum.to_us(),
372:                 data.aggregate.values.count,
373:             ) },
374:         },
375:     };
376: 
377:     try writer.print("tb.{[name]s}{[name_suffix]s}:{[value]d}|{[statsd_type]s}" ++
378:         "|#cluster:{[cluster]x:0>32},replica:{[replica]d}", .{
379:         .name = stat_name,
380:         .name_suffix = stat_suffix,
381:         .statsd_type = stat_type,
382:         .value = stat_value,
383:         .cluster = options.cluster,
384:         .replica = options.replica,
385:     });
386: 
387:     switch (stat) {
388:         inline else => |stat_data| {
389:             switch (stat_data.aggregate.event) {
390:                 inline else => |data| {
391:                     const Tags = @TypeOf(data);
392:                     if (@typeInfo(Tags) == .@"struct") {
393:                         const fields = std.meta.fields(@TypeOf(data));
394:                         inline for (fields) |data_field| {
395:                             comptime assert(!std.mem.eql(u8, data_field.name, "cluster"));
396:                             comptime assert(!std.mem.eql(u8, data_field.name, "replica"));
397:                             comptime assert(@typeInfo(data_field.type) == .int or
398:                                 @typeInfo(data_field.type) == .@"enum" or
399:                                 @typeInfo(data_field.type) == .@"union");
400: 
401:                             const data_field_value = @field(data, data_field.name);
402:                             try writer.writeByte(',');
403:                             try writer.writeAll(data_field.name);
404:                             try writer.writeByte(':');
405: 
406:                             if (@typeInfo(data_field.type) == .@"enum" or
407:                                 @typeInfo(data_field.type) == .@"union")
408:                             {
409:                                 try writer.print("{s}", .{@tagName(data_field_value)});
410:                             } else {
411:                                 try writer.print("{}", .{data_field_value});
412:                             }
413:                         }
414:                     } else {
415:                         assert(@TypeOf(data) == void);
416:                     }
417:                 },
418:             }
419:         },
420:     }
421:     try writer.writeByte('\n');
422: }
423: 
424: /// Returns an instance of a Struct (or void) with all fields set to what would result in the
425: /// longest length when formatted.
426: ///
427: /// Integers get maxInt, and Enums get a value corresponding to `enum_size_max()`.
428: fn struct_size_max(StructOrVoid: type) StructOrVoid {
429:     if (@typeInfo(StructOrVoid) == .void) return {};
430: 
431:     assert(@typeInfo(StructOrVoid) == .@"struct");
432:     const Struct = StructOrVoid;
433: 
434:     var output: Struct = undefined;
435: 
436:     for (std.meta.fields(Struct)) |field| {
437:         const type_info = @typeInfo(field.type);
438:         assert(type_info == .int or type_info == .@"enum");
439:         assert(type_info != .int or type_info.Int.signedness == .unsigned);
440:         switch (type_info) {
441:             .int => @field(output, field.name) = std.math.maxInt(field.type),
442:             .@"enum" => @field(output, field.name) =
443:                 std.enums.nameCast(field.type, enum_size_max(field.type)),
444:             else => @compileError("unsupported type"),
445:         }
446:     }
447: 
448:     return output;
449: }
450: 
451: /// Returns the longest @tagName for a given Enum.
452: fn enum_size_max(Enum: type) []const u8 {
453:     @setEvalBranchQuota(10_000);
454:     var tag_longest: []const u8 = "";
455:     for (std.meta.fieldNames(Enum)) |field_name| {
456:         if (tag_longest.len < field_name.len) {
457:             tag_longest = field_name;
458:         }
459:     }
460:     return tag_longest;
461: }
